dSIGS = [[dSIGS11, dSIGS21], [dSIGS12, dSIGS22]]
dNUFIS = [dNUFIS1, dNUFIS2]
dTOT1 = [x + y for x, y in zip(dABS1, dSIGS12)]
dTOT2 = [x + y for x, y in zip(dABS2, dSIGS21)]
dTOT = [dTOT1, dTOT2]
dSOURCE1 = [0.0 for _ in range(N)]
dSOURCE2 = [0.0 for _ in range(N)]
dSOURCE = [dSOURCE1, dSOURCE2]
v1 = np.ones(N)*v1
v2 = np.ones(N)*v2
v = [v1, v2]

## ILU PRE-CONDITIONER
precond = 1
geom_type = '1D'

#######################################################################################################
#solver_type = 'noise'

#######################################################################################################
output_dir = f'OUTPUTS/{case_name}'

#######################################################################################################
# FORWARD SIMULATION
solver_type = 'forward'

# Create directories
Utils.create_directories(solver_type, output_dir, case_name)

# Build matrices
matrix_builder = MatrixBuilderForward1D(group, N, TOT, SIGS, BC, dx, D, chi, NUFIS)
M, F = matrix_builder.build_forward_matrices()

# Solve
solver = SolverFactory.get_solver_power1D(solver_type, group, N, M, F, x, precond, tol=1E-10, eigenmodes=1)
keff, PHI = solver.solve()

# Post-processing
dim = len(PHI)

for d in range(dim):
    keff_fun = keff[d].real
    PHI_reshaped = np.reshape(PHI[d], (group, N))
    PostProcessor.save_output_power1D(output_dir, case_name, keff_fun, PHI_reshaped, solver_type)
    for g in range(group):
        Utils.plot_1D_power(solver_type, PHI_reshaped[g].real, x, g, output_dir=output_dir, varname=f'PHI_mode{d}', case_name=case_name, title=f'1D Plot of PHI{g+1}')
    
